1	export interface ItemSpec {
2	  type: string;
3	}
4	
5	export interface Customer {
6	  yearsWithMHPCO: number;
7	}
8	
9	export interface QuoteInput {
10	  customer: Customer;
11	  items: ItemSpec[];
12	}
13	
14	export interface QuoteResult {
15	  premium: number;
16	}
17	
18	const PROCESSING_FEE = 5;
19	const FIRST_INSURANCE_RATE = 0.1;
20	const RUNE_BLOCK_SIZE = 3;
21	const RUNE_BLOCK_PRICE = 60;
22	
23	const BASE_PREMIUMS: Record<string, number> = {
24	  sword: 100,
25	  amulet: 60,
26	  staff: 80,
27	  potion: 40,
28	  rune: 25,
29	  moonstone: 25,
30	};
31	
32	function basePremiumFor(item: ItemSpec): number {
33	  return BASE_PREMIUMS[item.type] ?? 0;
34	}
35	
36	function sumBasePremiums(items: ItemSpec[]): number {
37	  return items.reduce((sum, item) => sum + basePremiumFor(item), 0);
38	}
39	
40	function runeBlockAdjustment(items: ItemSpec[]): number {
41	  const runeCount = items.filter((item) => item.type === "rune").length;
42	  if (runeCount !== RUNE_BLOCK_SIZE) return 0;
43	  return RUNE_BLOCK_PRICE - RUNE_BLOCK_SIZE * basePremiumFor({ type: "rune" });
44	}
45	
46	export function quote(input: QuoteInput): QuoteResult {
47	  const policyBasePremium =
48	    sumBasePremiums(input.items) + runeBlockAdjustment(input.items);
49	  const firstInsuranceSurcharge = policyBasePremium * FIRST_INSURANCE_RATE;
50	  return {
51	    premium: Math.ceil(policyBasePremium + firstInsuranceSurcharge + PROCESSING_FEE),
52	  };
53	}
54	
55	export function claim(): unknown {
56	  return undefined;
57	}
